// DeckExportPanel.js
import React, { useState } from "react";
import { Save, Download } from "lucide-react";

// Backend endpoint
const SLIDESGPT_API = "http://localhost:8000/slidesgpt/generate";
const SLIDESGPT_DOWNLOAD = id => `http://localhost:8000/slidesgpt/download/${id}`;

// Defensive link getter (add more fallbacks if needed)
const getArticleLink = (art) =>
  art.link ||
  art.url ||
  art.source_url ||
  art.source ||
  (art.meta_data?.link ?? "N/A");

// Defensive score getter
const getArticleScore = (art) =>
  art.score ?? art.relevance_score ?? "--";


const processPromptForAPI = (promptText) => {
  // Clean URLs first
  const cleanedPrompt = promptText.replace(/(https?:\/\/[^\s\]]+)/g, (url) => {
    try {
      const urlObj = new URL(url);
      // Remove tracking parameters
      ['utm_medium', 'utm_source', 'utm_campaign', 'utm_content', 'utm_term'].forEach(param => {
        urlObj.searchParams.delete(param);
      });
      return urlObj.toString();
    } catch (e) {
      return url;
    }
  });

  // Properly escape for JSON if needed
  return cleanedPrompt.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
};

// Prompt builder
function buildSlidesGPTPrompt(title, template, contentOptions, articlesByCategory) {
  let prompt = `Generate a PowerPoint titled "${title}" using the "${template}".\n\n`;
  if (contentOptions.includeSummary) prompt += "Include an executive summary slide.\n";
  if (contentOptions.addCharts) prompt += "Add trend analysis charts if relevant.\n";
  prompt += "Organize the following content by category, summarize key insights for each article, and show each source link at the bottom:\n\n";
  Object.entries(articlesByCategory).forEach(([category, articles]) => {
    if (!articles.length) return;
    prompt += `## ${category}\n`;
    articles.forEach((art, idx) => {
      prompt += `- "${art.title}" [Score: ${getArticleScore(art)}]\n  - Summary: ${art.summary ?? "No summary"}\n  - Source: ${getArticleLink(art)}\n`;
    });
    prompt += "\n";
  });
  return prompt;
}

const DeckExportPanel = ({ categories, selectedArticles }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [slidesgptLinks, setSlidesgptLinks] = useState(null);
  const [showEmbed, setShowEmbed] = useState(false);

  const [title, setTitle] = useState("Gen AI & LLM Trends - July 2025");
  const [template, setTemplate] = useState("Standard Research Template");
  const [contentOptions, setContentOptions] = useState({
    includeSummary: true,
    generateSummaries: true,
    addCharts: true,
    sourceCitations: false,
  });

  // DEBUG: Print selectedArticles at every render
  console.log("[DeckExportPanel] selectedArticles:", selectedArticles);

  // Group by category
  const articlesByCategory = categories.reduce((acc, cat) => {
    const catArts = selectedArticles.filter(
      (a) => (a.category || "") === cat.id
    );
    acc[cat.name] = catArts;
    // DEBUG: Print category grouping results
    console.log(`[DeckExportPanel] ${cat.name}:`, catArts.map(a => ({
      id: a.id,
      title: a.title,
      link: getArticleLink(a),
      category: a.category
    })));
    return acc;
  }, {});

  async function handleExportPPT() {
    setIsExporting(true);
    setSlidesgptLinks(null);

    //const prompt = buildSlidesGPTPrompt(title, template, contentOptions, articlesByCategory);
    const prompt = `
        Generate a PowerPoint titled "Gen AI & LLM Trends - July 2025" using the "Standard Research Template".

        Include an executive summary slide.
        Add trend analysis charts if relevant.
        Organize the following content by category, summarize key insights for each article, and show each source link at the bottom:

        ## AI Adoption in Finance
        - "How AI Can Reduce Decision Fatigue for Asset Managers" [Score: 85]
        - Summary: In a discussion on FinextraTV, Phil Cox from Russell Investments and Roshan Shetty from Tech Mahindra explore how AI is helping to alleviate decision fatigue in asset management by enhancing analysis, portfolio construction, risk management, and trading strategies. They debate the ease of integrating AI into existing processes and highlight the prominence of information-based tools. The conversation underscores the transformative potential of AI in streamlining and optimizing asset management operations.
        - test.com
        `;
    console.log("[DeckExportPanel] SlidesGPT Prompt:\n", prompt);
    const safePrompt = processPromptForAPI(prompt);
    console.log("[DeckExportPanel] SAFE PROMPT SlidesGPT Prompt:\n", safePrompt);
    try {
      const res = await fetch(SLIDESGPT_API, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt }),
      });
      const data = await res.json();
      if (!data.id) throw new Error("SlidesGPT API failed!");

      setSlidesgptLinks({
        embed: data.embed,
        id: data.id
      });
    } catch (e) {
      alert("Export failed: " + (e?.message || "Unknown error"));
    }
    setIsExporting(false);
  }

  return (
    <div className="bg-white rounded-lg shadow p-6 mt-8">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-semibold">Generate Deck</h3>
        <div className="flex items-center gap-3">
          <button className="px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 flex items-center gap-2">
            <Save className="w-4 h-4" />
            Save Draft
          </button>
          <button
            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 flex items-center gap-2"
            onClick={handleExportPPT}
            disabled={isExporting}
          >
            {isExporting ? "Generating..." : <><Download className="w-4 h-4" /> Export PPT</>}
          </button>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="p-4 border rounded-lg">
          <h4 className="font-medium mb-2">Deck Settings</h4>
          <div className="space-y-3">
            <div>
              <label className="text-sm text-gray-600">Title</label>
              <input
                type="text"
                value={title}
                onChange={e => setTitle(e.target.value)}
                className="w-full mt-1 px-3 py-2 border rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <div>
              <label className="text-sm text-gray-600">Template</label>
              <select
                value={template}
                onChange={e => setTemplate(e.target.value)}
                className="w-full mt-1 px-3 py-2 border rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option>Standard Research Template</option>
                <option>Executive Summary Template</option>
                <option>Detailed Analysis Template</option>
              </select>
            </div>
          </div>
        </div>
        <div className="p-4 border rounded-lg">
          <h4 className="font-medium mb-2">Content Options</h4>
          <div className="space-y-2">
            <label className="flex items-center gap-2">
              <input type="checkbox" checked={contentOptions.includeSummary} onChange={e => setContentOptions({ ...contentOptions, includeSummary: e.target.checked })} className="rounded" />
              <span className="text-sm">Include executive summary</span>
            </label>
            <label className="flex items-center gap-2">
              <input type="checkbox" checked={contentOptions.generateSummaries} onChange={e => setContentOptions({ ...contentOptions, generateSummaries: e.target.checked })} className="rounded" />
              <span className="text-sm">Generate article summaries</span>
            </label>
            <label className="flex items-center gap-2">
              <input type="checkbox" checked={contentOptions.addCharts} onChange={e => setContentOptions({ ...contentOptions, addCharts: e.target.checked })} className="rounded" />
              <span className="text-sm">Add trend analysis charts</span>
            </label>
            <label className="flex items-center gap-2">
              <input type="checkbox" checked={contentOptions.sourceCitations} onChange={e => setContentOptions({ ...contentOptions, sourceCitations: e.target.checked })} className="rounded" />
              <span className="text-sm">Include source citations</span>
            </label>
          </div>
        </div>
      </div>
      {slidesgptLinks && (
        <div className="mt-6 space-y-4">
          <a
            href={SLIDESGPT_DOWNLOAD(slidesgptLinks.id)}
            download
            target="_blank"
            rel="noopener noreferrer"
            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 flex items-center gap-2"
          >
            <Download className="w-4 h-4" />
            Download PPTX
          </a>
          <button
            className="px-4 py-2 border border-gray-300 rounded-lg flex items-center gap-2"
            onClick={() => setShowEmbed(v => !v)}
          >
            <Save className="w-4 h-4" />
            {showEmbed ? "Hide Online Preview" : "Show in PowerPoint Online"}
          </button>
          {showEmbed && slidesgptLinks.embed && (
            <div className="my-6">
              <iframe
                src={slidesgptLinks.embed}
                style={{ width: "100%", minHeight: "600px", border: "1px solid #eee", borderRadius: "10px" }}
                allowFullScreen
                title="PowerPoint Online Preview"
              ></iframe>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default DeckExportPanel;
